187: // isPostStartHookRegistered checks whether a given PostStartHook is registered
188: func (s *GenericAPIServer) isPostStartHookRegistered(name string) bool {
189: 	s.postStartHookLock.Lock()
190: 	defer s.postStartHookLock.Unlock()
191: 	_, exists := s.postStartHooks[name]
192: 	return exists
193: }
